        renderActions(row) {
            var self = this;
            let rtnActionArray = [];
            // Map commonly used flags/properties from the row so that the
            // enable/disable logic matches the old Razor view as closely as possible.
            const billId = row.BILL_ID;
            const status = row.STATUS_CODE;
            const billNumber = row.BILL_NUMBER;
            const isDraftBill = billNumber === 'Draft Mode';
            const isRecurring = row.IS_RECURRING == 1;
            const recurringStatus = row.RECURRING_STATUS;
            const hasBillingDivision = !!row.BILLING_DIVISION;
            const hasSummaryTemplate = !!row.IS_SUMMARY;
            const hasDetailedTemplate = !!row.IS_DETAILED;
            const isUSICFeature = self.isCheckExtraFeatureUSICBILLING;       // ViewBag.USICFeature == "Yes"
            const isExtraFeature = self.isCheckExtraFeatureUtilityBilling;   // ViewBag.ExtraFeature == "Yes"
            const isPMOrCA = self.UserType === 'PM' || self.UserType === 'CA';

            const editDisabledStatuses = [
                'CLBPAD',
                'CLBBDBT',
                'CLBPPAD',
                'CLBDSPT',
                'CLBCNCL',
                'RLSTOWORKDAY',
                'CANPWORKDAY'
            ];

            self.listActions.forEach(actionItem => {
                //debugger;
                let action = { ...actionItem };

                // // If privilege explicitly denies this action, hide/disable it
                // if (self.actionPrivileges.hasOwnProperty(action.title) && !self.actionPrivileges[action.title]) {
                //     action.isVisible = true;
                //     action.isDisabled = true;
                //     action.href = 'javascript:void(0)';
                //     action.callbackfunction = null;
                //     rtnActionArray.push(action);
                //     return;
                // }
                // // If privilege explicitly denies this action, hide it
                // if (self.actionPrivileges.hasOwnProperty(action.title) && !self.actionPrivileges[action.title]) {
                //     action.isVisible = false;
                //     rtnActionArray.push(action);
                //     return;
                // }
                switch (action.title) {
                    case 'Edit':
                        // Match Razor rules:
                        // - Only PM / CA can edit
                        // - For recurring invoices: disallow when released to workday (RLSTOWORKDAY) or sent (CLBSND)
                        // - For non‑recurring invoices: disallow for paid / bad‑debt / partial‑paid / disputed / cancelled /
                        //   released / cancel‑pending
                        action.isVisible = true;
                        if (!isPMOrCA) {
                            action.isDisabled = true;
                        } else if (isRecurring) {
                            action.isDisabled =
                                status === 'RLSTOWORKDAY' ||
                                status === 'CLBSND' ||
                                recurringStatus === 'STOP';
                        } else {
                            action.isDisabled = editDisabledStatuses.includes(status);
                        }
                        if (isUSICFeature)
                            action.href = `/ClientInvoice/Update/${billId}`;
                        else
                            action.href = `/AddInvoice/Edit/${billId}`;
                        break;
                    case 'ViewBill':
                        // Rough equivalent of the various "View Invoice" links in Razor:
                        // - When USIC feature is on, invoice is always viewable
                        // - When USIC feature is off, hide this for draft invoices
                        if (isUSICFeature) {
                            action.isVisible = false;
                            action.isDisabled = false;
                        } else {
                            action.isVisible = true;
                            action.isDisabled = isDraftBill;
                        }
                        break;
                    case 'SendBill':
                        // Razor: Send Invoice is only available when
                        // - USIC feature is NOT enabled
                        // - BillNumber is not "Draft Mode"
                        action.isVisible = !isUSICFeature;
                        action.isDisabled = isDraftBill;
                        break;
                    case 'View Summary':
                        // Razor:
                        // - When ExtraFeature == "Yes": enable only if the row has a summary template
                        // - When USICFeature == "Yes": always allow "View Summary"
                        if (isExtraFeature) {
                            action.isVisible = true;
                            action.isDisabled = !hasSummaryTemplate;
                        } else if (isUSICFeature) {
                            action.isVisible = true;
                            action.isDisabled = false;
                        } else {
                            action.isVisible = false;
                        }
                        action.href = `/InvoiceReport/SummaryInvoice?billId=${encodeURIComponent(billId)}`;
                        break;
                    case 'View Invoice Backup':
                        // Razor: Invoice backup links only appear when USIC feature is enabled
                        action.isVisible = isUSICFeature;
                        action.isDisabled = false;
                        action.href = `/InvoiceReport/InvoiceBackup?billId=${encodeURIComponent(billId)}`;
                        break;
                    case "PaySlip":
                        action.isVisible = isUSICFeature;

                        if (isUSICFeature) {
                            action.isVisible = false;
                            action.isDisabled = false;
                        } else {
                            action.isVisible = true;
                            action.isDisabled = status == "CLBPAD" || status == "CLBPPAD" ? false : true;
                        }
                        break;
                    case 'Payment':
                        // Razor: Payment only active when status is Sent (CLBSND) or Partial Paid (CLBPPAD)
                        // and hidden for client users.
                        action.isVisible = self.UserType == 'CL' ? false : true;
                        action.isDisabled = !(status == "CLBSND" || status == "CLBPPAD");
                        break;
                    case 'View Talygen Backup':
                        // Razor: Talygen backup visible only when USICFeature == "Yes"
                        // and user is PM/CA and status != cancelled.
                        action.isVisible = isUSICFeature && isPMOrCA;
                        action.isDisabled = status === 'CLBCNCL';
                        action.href = `/InvoiceReport/TalygenBackup?billId=${encodeURIComponent(billId)}`;
                        break;
                    case 'InvoiceHistory':
                        // Razor: disabled when bill is still in "Draft Mode"
                        action.isVisible = true;
                        action.isDisabled = isDraftBill;
                        break;
                    case 'InvoiceHistoryChange':
                        action.isVisible = true;
                        break;
                    case 'Attachment':
                        action.isVisible = true;
                        action.userGuide = self.$t('ViewAttachedFile') + ' (' + row.ATTACHMENT_COUNT + ')';
                        break;


                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },

