        ConvertJSONToCSV: function (data, filename, showHeader) {

            var vm = this;

            if (!data || !Array.isArray(data) || data.length === 0) {
                console.log("No valid data to convert.");
                return;
            }

            // Header map for custom Excel column names
            const headerMap = {
                BILL_NUMBER: "Invoice No",
                CLIENT_NAME: "Contract",
            };

            // Get visible columns from Headers array, respecting feature flags
            const visibleColumns = vm.Headers
                .filter(column => {
                    // Check base visibility
                    if (!column.VISIBLE) return false;

                    // Apply same visibility rules as in FetchData
                    if (vm.isCheckExtraFeatureUSICBILLING) {
                        if (column.COLUMN_NAME == 'Company' ||
                            column.COLUMN_NAME == 'PROJECT_NAME' ||
                            column.COLUMN_NAME == 'PARENT_INVOICE' ||
                            column.COLUMN_NAME == 'RECURRING_FREQUENCY' ||
                            column.COLUMN_NAME == 'BILL_DUE_DATE' ||
                            column.COLUMN_NAME == 'Outstanding' ||
                            column.COLUMN_NAME == 'CONVERT_AMOUNT' ||
                            column.COLUMN_NAME == 'CONVERT_OUTSTANDING_AMOUNT') {
                            return false;
                        }
                    }

                    return true;
                })
                .sort((a, b) => (a.DISPLAY_ORDER || 0) - (b.DISPLAY_ORDER || 0));

            // Build headers array with display names
            // Use headerMap if available, otherwise use DISPLAY_NAME
            // Add a trailing space to headers to help Excel auto-size columns properly
            const csvHeaders = visibleColumns.map(column => {
                const headerName = headerMap[column.COLUMN_NAME] || column.DISPLAY_NAME;
                return headerName + ' ';
            });

            // Helper function to format cell value based on column type
            const formatCellValue = (row, column) => {
                const columnName = column.COLUMN_NAME;
                let value = '';

                switch (columnName) {
                    case 'STATUS':
                        // Use getStatusLabel to match display
                        value = vm.getStatusLabel(row);
                        break;
                    case 'BILLING_PERIOD':
                        // Use getInvoiceBillingPeriod to match display
                        value = vm.getInvoiceBillingPeriod(row);
                        break;
                    case 'BILL_ISSUE_DATE':
                        // Format CREATED_AT date
                        if (row.CREATED_AT) {
                            value = vm.$options.filters.formatDate(row.CREATED_AT);
                        }
                        break;
                    case 'BILL_DUE_DATE':
                        // Format BILL_DUE_DATE
                        if (row.BILL_DUE_DATE) {
                            value = vm.$options.filters.formatDate(row.BILL_DUE_DATE);
                        }
                        break;
                    case 'BILL_NET_TOTAL':
                        // Format as currency
                        if (row.BILL_NET_TOTAL !== undefined && row.BILL_NET_TOTAL !== null) {
                            value = vm.$n(row.BILL_NET_TOTAL, "currency", vm.$getLocaleByCurrency(vm.getCurrencyForRow(row)));
                        }
                        break;
                    case 'CONVERT_AMOUNT':
                        // Format as currency
                        if (row.CONVERT_AMOUNT !== undefined && row.CONVERT_AMOUNT !== null) {
                            value = vm.$n(row.CONVERT_AMOUNT, "currency", vm.$getLocaleByCurrency(vm.getCurrencyForRow(row)));
                        }
                        break;
                    case 'Outstanding':
                        // Format BILL_NET_TOTAL as currency
                        if (row.BILL_NET_TOTAL !== undefined && row.BILL_NET_TOTAL !== null) {
                            value = vm.$n(row.BILL_NET_TOTAL, "currency", vm.$getLocaleByCurrency(vm.getCurrencyForRow(row)));
                        }
                        break;
                    case 'CONVERT_OUTSTANDING_AMOUNT':
                        // Format as currency
                        if (row.CONVERT_OUTSTANDING_AMOUNT !== undefined && row.CONVERT_OUTSTANDING_AMOUNT !== null) {
                            value = vm.$n(row.CONVERT_OUTSTANDING_AMOUNT, "currency", vm.$getLocaleByCurrency(vm.getCurrencyForRow(row)));
                        }
                        break;
                    case 'Company':
                        // Use COMPANY_NAME
                        value = row.COMPANY_NAME || '';
                        break;
                    case 'BILL_NUMBER':
                        // Just the bill number (no link)
                        value = row.BILL_NUMBER || '';
                        break;
                    default:
                        // For other columns, use the column name directly
                        value = row[columnName] !== undefined && row[columnName] !== null
                            ? String(row[columnName])
                            : '';
                }

                return value;
            };

            // Build rows
            const rows = data.map((row) => {
                return visibleColumns
                    .map((column) => {
                        let cellValue = formatCellValue(row, column);

                        // Escape CSV special characters
                        if (
                            cellValue.includes(",") ||
                            cellValue.includes("\n") ||
                            cellValue.includes('"')
                        ) {
                            cellValue = `"${String(cellValue).replace(/"/g, '""')}"`;
                        }

                        return cellValue;
                    })
                    .join(",");
            });

            // Combine headers and rows
            const csvContent = (showHeader ? [csvHeaders.join(",")] : [])
                .concat(rows)
                .join("\n");

            // Add UTF-8 BOM for better Excel compatibility
            const BOM = '\uFEFF';
            const csvWithBOM = BOM + csvContent;

            // Create and download file
            const blob = new Blob([csvWithBOM], {
                type: "text/csv;charset=utf-8;",
            });
            const link = document.createElement("a");
            link.setAttribute("href", URL.createObjectURL(blob));
            link.setAttribute("download", `${filename}.csv`);
            link.click();
