        getInvoiceUrl(item) {
            if (this.isCheckExtraFeatureUSICBILLING) {
                return `${process.env.VUE_APP_CURRENT_SITE_ROOT_URL}/ClientInvoice/Update/${item.BILL_ID}`;
            } else {
                // Vue Router path version (not push)
                return this.$router.resolve({
                    name: 'AddInvoice',
                    params: { action: 'Edit', id: item.BILL_ID }
                }).href;
            }
        },

        handleEdit(item, event) {
            // Only intercept LEFT click
            if (event.ctrlKey || event.metaKey || event.button === 1) return;

            event.preventDefault();

            if (this.isCheckExtraFeatureUSICBILLING) {
                window.location.href = this.getInvoiceUrl(item);
            } else {
                this.$router.push({
                    name: 'AddInvoice',
                    params: { action: 'Edit', id: item.BILL_ID }
                });
            }
        },
