<template>
    <section>
        <div class="my-popups">
            <loader :is-visible="isLoading"></loader>
            <div class="modal d-block">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header theme-primary partition-full d-flex">
                            <h5 class="modal-title">{{ $t("Invoice") }} {{ $t("History") }}</h5>
                            <button type="button" class="close" @click="Close">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                        </div>

                        <div class="modal-body">
                            
                                

                                <div class="listing mt-2" v-if="isInvoice">
                                    <div id="divmemb" class="table-responsive table-fix-header">
                                        <table class="table table-bordered mt-0 w-100">
                                            <thead class="thead-bg">
                                                <tr>
                                                   <th>{{ $t("Change") }} {{ ' ' }} {{ $t("Date") }}</th>
                                                    <th>{{ $t("Bill#") }}</th>
                                                    <th>{{ $t("Client") }}</th>
                                                    <th>{{ $t("Project") }}</th>
                                                    <th>{{ $t("IssueDate") }}</th>
                                                    <th>{{ $t("DueDate") }}</th>
                                                    <th>{{ $t("Amount") }}</th>
                                                    <th>{{ $t("DateFrom") }}</th>
                                                    <th>{{ $t("DateTo") }}</th>
                                                    <th>{{ $t("DueDate") }} {{ ' ' }} {{$t("Comment") }}</th>
                                                    <th>{{ $t("Terms")}}</th>
                                                    <th>{{ $t("Template")}}</th>
                                                    <th>{{ $t("Action") }}</th>


                                                     
                                                   
                                                    
                                                    
                                                    
                                                </tr>
                                            </thead>
                                            <tbody v-if="InvoiceHistoryDetails.length > 0">
                                                
                                                    <tr v-for="(childInvoice,index) in InvoiceHistoryDetails" :key="index"> 
                                                        <td>
                                                            {{ formatDate(childInvoice.bill_history_changed_at) }}
                                                        </td>
                                                        <td>
                                                            {{ childInvoice.bill_number }}
                                                        </td>
                                                        <td>
                                                            {{ childInvoice.bill_to }}
                                                        </td>
                                                        <td>
                                                            {{ childInvoice.project_name }}
                                                        </td>
                                                       
                                                        <td>
                                                            {{ formatDate(childInvoice. bill_issue_date) }}
                                                        </td>
                                                        <td>
                                                            {{ formatDate(childInvoice.bill_due_date) }}
                                                        </td>
                                                        <td>
                                                            {{  $n(childInvoice.bill_net_total, "currency", $getLocaleByCurrency(childInvoice.Currency)) }}
                                                           
                                                        </td>
                                                         <td>
                                                            {{ formatDate(childInvoice.bill_date_from) }}
                                                        </td>
                                                         <td>
                                                            {{ formatDate(childInvoice.bill_date_to) }}
                                                        </td>
                                                         <td>
                                                            {{ childInvoice.bill_due_date_comment }}
                                                        </td>
                                                        <td>
                                                            {{ childInvoice.Terms }}
                                                        </td>
                                                          <td>
                                                            {{ childInvoice.Template_Name }}
                                                        </td>
                                                          
                                                        <td class="text-center mobile-action single-action">
                                                          <a title="View Bill" href="javascript:void(0)" @click="handleViewBill(childInvoice)" >
                                                          <em class="fa fa-eye action-icon "></em>  
                                                          </a>
                                                        </td>
                                                        
                                                    </tr>
                                            </tbody>
                                            <tbody v-else>
                                                <tr>
                                                    <td colspan="13" class="text-center text-danger py-3">
                                                        {{$t('NoRecordfound') }}
                                                    </td>
                                                </tr>
                                            </tbody>
                                        </table>
                                    </div>
                                </div>
<div v-else>
                                    <InvoiceTemplate v-if="isTemplate" :details="templatedata" 
            :hitFrom="'MainInvoice'" @backtoInvoiceList="backtoInvoiceList"/>
                               
                    </div>       
                        </div>
                    </div>
                </div>
            </div>
        </div>
       
    </section>
</template>

<script>
import DataService from '../../../services/DataService';
import InvoiceTemplate from './InvoiceTemplate.vue';
import moment from 'moment';
export default {
    name: 'ClientBillListing',
    components: { InvoiceTemplate},
    props: {
        BillId: { type: Number }
    },
    data() {
        return {
            isLoading: false,
             InvoiceHistoryDetails: [],
             isTemplate: false,
             templatedata: {},
             isInvoice: true,
           
        };
    },
    created() {
       // debugger;
        this.fetchData();
    },
    methods: {
        async fetchData() {
            debugger
            this.isLoading = true;
            try {
                debugger
                const response = await DataService.GetInvoiceHistoryDetails(`billId=${this.BillId}`);
                //const groupedData = this.groupInvoiceData(response.data);
                 //this.InvoiceHistoryDetails = response.data.result;
                 this.InvoiceHistoryDetails = JSON.parse(response.data.result).data;
                

            } catch (error) {
                console.error("Error fetching invoice data", error);
            } finally {
                this.isLoading = false;
            }
        },
        backtoInvoiceList() {
            this.isInvoice = true;
            this.isTemplate = false;
           
        },
      async handleViewBill(item) {
        //debugger
            //const params = `SysStartTime=${item.SysStartTime}`;
            //const params = `SysStartTime=${encodeURIComponent(item.SysStartTime)}&SysEndTime=${encodeURIComponent(item.SysEndTime)}`;
             //const params = `billId=${item.invoiceId_Enc}&handleViewBill=${encodeURIComponent(item.SysStartTime)}&SysEndTime=${encodeURIComponent(item.SysEndTime)}`;
             const params = `billId=${item.invoiceId_Enc}&billHistroyId=${item.invoiceHistoryId_Enc}`;
            
            const response = await DataService.getInvoiceBillHistoryDetails(params);
            this.templatedata = response.data.result.data;
            this.isInvoice = false;
            this.isTemplate = true;
        },
       
        Close() {
            this.$parent.isInvoiceHistoryChange = false;
        },
        textCounter() {
            this.textCountertlength = 2000 - this.comment.length
        },
        formatDate: function (value) {
    if (!value) return '';
    return moment(value).format('MM/DD/YYYY');
},
        
       
        getStatusClass(statusCode) {
            switch (statusCode) {
                case "CLBSND":
                return "bg-success";
                case "CLBDSPT":
                return "bg-info";
                case "CLBPAD":
                return "bg-primary";
                case "CLBRSTP":
                return "bg-danger";
                case "CLBBDBT":
                return "bg-dark";
                case "CLBDFT":
                return "bg-warning";
                default:
                return "bg-secondary";
        }
    }

    },
};
</script>